{"command":"python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp 3171 3171 <<'CODEEOF'
  // select(C1 && C2, c, select(C1, a, b)) -> select(C1, select(C2, c, a), b)
  if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
    Value *C1 = FalseSI->getCondition();
    Value *A = FalseSI->getTrueValue();
    Value *B = FalseSI->getFalseValue();
    Value *C2;
    if (match(CondVal, m_c_LogicalAnd(m_Specific(C1), m_Value(C2))) &&
        FalseSI->hasOneUse()) {
      Value *NewSel = Builder.CreateSelect(C2, TrueVal, A);
      NewSel->takeName(&SI);
      replaceOperand(SI, 0, C1);
      replaceOperand(SI, 1, NewSel);
      replaceOperand(SI, 2, B);
      return &SI;
    }
  }

CODEEOF
"}

